// Enable Milky Way rendering
MilkyWay.setFlagShow(true);

// Disable Milky Way rendering
MilkyWay.setFlagShow(false);

// Read current state (alternative method)
var visible = core.getStelProperty('MilkyWay.flagMilkyWayDisplayed');

// Make the Milky Way brighter
MilkyWay.setIntensity(1.5);

// Make the Milky Way dimmer
MilkyWay.setIntensity(0.5);

// Reset to default
MilkyWay.setIntensity(1.0);

// Make Milky Way colors more vivid
MilkyWay.setSaturation(1.3);

// Make Milky Way black and white
MilkyWay.setSaturation(0.0);

// Reset to natural colors
MilkyWay.setSaturation(1.0);

// Set Milky Way to natural white
var white = core.vec3f(1.0, 1.0, 1.0);
MilkyWay.setColor(white);

// Set a subtle warm tint
var warm = core.vec3f(1.0, 0.95, 0.9);
MilkyWay.setColor(warm);

// Set a bluish tint
var blueish = core.vec3f(0.85, 0.9, 1.0);
MilkyWay.setColor(blueish);
